import React, { useState, useEffect } from 'react';
import axios from 'axios';

const GalleryPage = () => {
  const [images, setImages] = useState([]);

  useEffect(() => {
    const fetchImages = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/galleries');
        console.log("Fetched Images:", res.data);  // ✅ Debugging log
        setImages(res.data);
      } catch (error) {
        console.error("Error fetching gallery images:", error);
      }
    };
    fetchImages();
  }, []);

  return (
    <div className="container mx-auto p-6">
      <h2 className="text-3xl font-bold text-gray-800">Proofing Gallery</h2>
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6">
        {images.map((img) => (
          <div key={img.id} className="bg-white shadow-md rounded-lg p-4">
            <img 
              src={img.imageUrl} 
              alt={img.title} 
              className="w-full h-auto rounded-lg object-cover" 
              onError={(e) => e.target.src = "https://via.placeholder.com/300"} // ✅ Fallback image
            />
            <p className="text-center mt-2 font-semibold">{img.title}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default GalleryPage;
